import re
from collections import Counter
def validate_tool_output(output: str) -> bool:
    hallucination_patterns = [
        r'\b(I\s+(don\'t|cannot|unable)\s+know)\b',
        r'\b(error|failure|exception)\b',
        r'\b(404|500|not found)\b'
    ]
    for pattern in hallucination_patterns:
        if re.search(pattern, output, re.IGNORECASE):
            return False

    # Entropy check for gibberish
    chars = [c for c in output.lower() if c.isalpha()]
    if len(chars) > 10:
        entropy = -sum((count/len(chars)) * (count/len(chars)).log() 
                      for count in Counter(chars).values())
        return entropy > 2.5
    return True

