from crewai import Agent, Task, Crew
from typing import Dict, Set

class LoopSafeCrew(Crew):
    def __init__(self, *args, max_delegations=3, **kwargs):
        super().__init__(*args, **kwargs)
        self.delegation_counts: Dict[str, int] = {}
        self.max_delegations = max_delegations
        self.blacklisted_pairs: Set[tuple] = set()

    def safe_delegate(self, from_agent: str, to_agent: str, task: Task) -> bool:
        pair = (from_agent, to_agent)
        if pair in self.blacklisted_pairs:
            return False

        self.delegation_counts[to_agent] = self.delegation_counts.get(to_agent, 0) + 1
        if self.delegation_counts[to_agent] > self.max_delegations:
            self.blacklisted_pairs.add(pair)
            return False
        return True

from crewai import Task

def create_validation_task(original_task: Task) -> Task:
    return Task(
        description=f"""
        Validate the previous tool output before proceeding.
        Original task: {original_task.description}
        Tool output: {{previous_output}}

        Respond with VALID or INVALID.
        If INVALID, explain why and suggest correction.
        """",
        agent=original_task.agent,
        context=[original_task],
        expected_output="VALID or INVALID with explanation"
    )
